#!/usr/bin/env node
/**
 * TYFYS accounting snapshot (money in/out + payroll due)
 *
 * Produces a single, shareable markdown report for a given window.
 *
 * Inputs:
 * - Stripe balance transactions (money in/out + fees)
 * - Sales payroll JSON (generated by sales-payroll-calc.mjs)
 * - Fixed payroll + fixed overhead assumptions
 */

import fs from 'node:fs/promises';
import path from 'node:path';
import Stripe from 'stripe';

import { loadEnvLocal } from '../lib/load-env-local.mjs';

loadEnvLocal();

function getArg(name, def) {
  const idx = process.argv.indexOf(name);
  if (idx === -1) return def;
  const v = process.argv[idx + 1];
  if (!v || v.startsWith('--')) return def;
  return v;
}

const fromArg = getArg('--from', null);
const toArg = getArg('--to', null);
if (!fromArg || !toArg) {
  console.error('Usage: node scripts/tyfys/accounting-payroll-report.mjs --from YYYY-MM-DD --to YYYY-MM-DD');
  process.exit(1);
}

const from = new Date(`${fromArg}T00:00:00-05:00`);
const to = new Date(`${toArg}T23:59:59-05:00`);

const stripeKey = process.env.STRIPE_API_KEY;
if (!stripeKey) throw new Error('Missing STRIPE_API_KEY');
const stripe = new Stripe(stripeKey, { apiVersion: '2024-06-20' });

const FIXED_OVERHEAD_MONTHLY = [
  { name: 'Spectrum business (incl RingCentral)', amount: 350 },
  { name: 'Zoho CRM', amount: 600 },
  { name: 'Zapier', amount: 150 },
  { name: 'ChatGPT', amount: 200 },
  { name: 'Office rent', amount: 1100 },
];

const PAYROLL_FIXED_BIWEEKLY = [
  { name: 'Richard salary', amount: 4000 },
  { name: 'Devin salary', amount: 1000 },
];

function cents(n) { return Math.round(Number(n) * 100); }
function fmtCents(v) {
  const sign = v < 0 ? '-' : '';
  const abs = Math.abs(v);
  return `${sign}$${(abs / 100).toFixed(2)}`;
}

async function listAll(listFn, params) {
  const out = [];
  let starting_after;
  while (true) {
    const res = await listFn({ ...params, limit: 100, ...(starting_after ? { starting_after } : {}) });
    out.push(...res.data);
    if (!res.has_more) break;
    starting_after = res.data[res.data.length - 1].id;
  }
  return out;
}

function daysBetweenInclusive(a, b) {
  const ms = (b.getTime() - a.getTime());
  return Math.max(1, Math.ceil(ms / (24*3600*1000)) + 1);
}

async function loadSalesPayrollJson() {
  const p = path.resolve('memory/tyfys', `sales-payroll_${fromArg}_to_${toArg}.json`);
  const txt = await fs.readFile(p, 'utf8');
  return { path: p, json: JSON.parse(txt) };
}

(async function main() {
  const fromSec = Math.floor(from.getTime() / 1000);
  const toSec = Math.floor(to.getTime() / 1000);

  const balanceTx = await listAll(stripe.balanceTransactions.list.bind(stripe.balanceTransactions), {
    created: { gte: fromSec, lte: toSec },
  });

  const stripeTotals = { grossIn: 0, grossOut: 0, fees: 0, net: 0, count: 0, byType: {} };
  for (const bt of balanceTx) {
    stripeTotals.count += 1;
    if (bt.amount > 0) stripeTotals.grossIn += bt.amount;
    if (bt.amount < 0) stripeTotals.grossOut += -bt.amount;
    stripeTotals.fees += bt.fee;
    stripeTotals.net += bt.net;
    stripeTotals.byType[bt.type] ||= { count: 0, net: 0 };
    stripeTotals.byType[bt.type].count += 1;
    stripeTotals.byType[bt.type].net += bt.net;
  }

  const { path: salesPath, json: sales } = await loadSalesPayrollJson();

  const fixedPayrollCents = PAYROLL_FIXED_BIWEEKLY.reduce((s, x) => s + cents(x.amount), 0);
  const salesPayrollCents = cents(sales?.grandTotal || 0);

  // Overhead: prorate monthly overhead across the window by days.
  // This is “accrual-ish”, not cash timing.
  const overheadMonthlyCents = FIXED_OVERHEAD_MONTHLY.reduce((s, x) => s + cents(x.amount), 0);
  const days = daysBetweenInclusive(from, to);
  const overheadDailyCents = Math.round(overheadMonthlyCents / 30); // simple
  const overheadWindowCents = overheadDailyCents * days;

  const totalObligations = fixedPayrollCents + salesPayrollCents + overheadWindowCents;

  const netAfter = stripeTotals.net - totalObligations;
  const grossAfter = stripeTotals.grossIn - totalObligations;

  const md = [];
  md.push(`# TYFYS accounting snapshot`);
  md.push('');
  md.push(`Window (ET): **${fromArg} → ${toArg}**`);
  md.push('');

  md.push(`## Money in/out (Stripe balance transactions)`);
  md.push(`- Gross collected (inflows): **${fmtCents(stripeTotals.grossIn)}**`);
  md.push(`- Gross outflows (refunds/adjustments/etc): **${fmtCents(stripeTotals.grossOut)}**`);
  md.push(`- Fees: **${fmtCents(stripeTotals.fees)}**`);
  md.push(`- Net: **${fmtCents(stripeTotals.net)}**`);
  md.push('');

  md.push('## Payroll due (this window)');
  md.push(`### Fixed payroll (biweekly)`);
  for (const p of PAYROLL_FIXED_BIWEEKLY) md.push(`- ${p.name}: $${p.amount}`);
  md.push(`- Fixed payroll subtotal: **${fmtCents(fixedPayrollCents)}**`);
  md.push('');

  md.push('### Sales payroll (variable)');
  for (const s of (sales?.summary || [])) {
    md.push(`- ${s.rep}: $${s.total} (deals $${s.dealTotal} + call bonus $${s.callBonus || 0} + extra bonus $${s.extraBonus || 0})`);
  }
  md.push(`- Sales payroll subtotal: **${fmtCents(salesPayrollCents)}**`);
  md.push('');

  md.push('## Fixed overhead (accrued)');
  for (const o of FIXED_OVERHEAD_MONTHLY) md.push(`- ${o.name}: $${o.amount}/mo`);
  md.push(`- Overhead monthly total: $${(overheadMonthlyCents/100).toFixed(0)}/mo`);
  md.push(`- Window accrual (${days} days @ ~$${(overheadDailyCents/100).toFixed(2)}/day): **${fmtCents(overheadWindowCents)}**`);
  md.push('');

  md.push('## Where we are (simple runway)');
  md.push(`- Total obligations (fixed payroll + sales payroll + overhead accrual): **${fmtCents(totalObligations)}**`);
  md.push(`- Net after obligations: **${fmtCents(netAfter)}**`);
  md.push(`- Gross after obligations (shows fee/refund drag): **${fmtCents(grossAfter)}**`);
  md.push('');
  md.push(`Sources:`);
  md.push(`- Sales payroll: ${salesPath}`);

  await fs.mkdir(path.resolve('memory/tyfys'), { recursive: true });
  const outPath = path.resolve('memory/tyfys', `accounting-snapshot_${fromArg}_to_${toArg}.md`);
  await fs.writeFile(outPath, md.join('\n') + '\n', 'utf8');

  process.stdout.write(`Wrote ${outPath}\n`);
})().catch(err => {
  console.error(err?.stack || String(err));
  process.exit(1);
});
